#include<bits/stdc++.h>
using namespace std;
int n,p,a[100005],b[100005];
double sum=0;
bool pan(double t){
    double q=p*t;
	double sum=0;
	for(int i=0;i<n;i++){
		if(a[i]*t<=b[i]){
			continue;
		}
		sum+=(a[i]*t-b[i]);
	}
	return sum<=q;
}
int main(){
    double l=0,ans=0;
    double r=1e10;
    cin>>n>>p;
	for(int i=0;i<n;i++){
		cin>>a[i]>>b[i];
		sum+=a[i];
	}
	if(sum<=p){
		cout<<-1;
		return 0;
	}
    while(r-l>=1e-6){
        double mid=(l+r)/2;
        if(pan(mid)){
            ans=mid;
            l=mid+0.0000000001;
        }else{
            r=mid-0.0000000001;
        }
    }
    printf("%.10lf",ans);
    return 0;
}
